(function appMain() {
  const TAKE_RATE = 0.25;
  const COLORS = {
    accent: "#e9c46a",
    blue: "#8ab4ff",
    purple: "#c4a7ff",
    green: "#72d6a3",
    red: "#ef7d7d",
    muted: "#a7aab7",
  };
  const state = {
    rawBookings: [],
    rawTalent: [],
    rawWaitlist: [],
    bookings: [],
    talent: [],
    waitlist: [],
    activeTab: "revops",
    sortTalentBy: "paidRevenue",
    sortTalentDir: "desc",
  };

  const bookingRequired = ["coreTalent", "date", "geoCity", "geoCountry", "geoState", "priceFinal", "priceDiscount", "priceComped", "primaryGuest", "status"];
  const talentRequired = ["name", "category", "categoryOrg", "categoryStyle", "categorySub", "accountStatus", "isAvailable", "isLive", "onboardingStatus", "price", "createdDate"];
  const waitlistRequired = ["coreTalent", "fanEmail", "status", "Creation Date"];

  const $ = (id) => document.getElementById(id);
  const norm = (v) => String(v ?? "").trim().toLowerCase();
  const txt = (v, fallback = "") => String(v ?? "").trim() || fallback;
  const num = (v) => {
    if (v == null || v === "") return 0;
    const n = Number(String(v).replace(/[$,]/g, "").trim());
    return Number.isFinite(n) ? n : 0;
  };
  const parseDate = (v) => {
    if (!v) return null;
    if (v instanceof Date) return Number.isNaN(v.getTime()) ? null : v;
    if (typeof v === "number" && Number.isFinite(v)) return new Date(Math.round((v - 25569) * 86400 * 1000));
    const s = String(v).trim();
    if (!s) return null;
    const parsed = new Date(s);
    return Number.isNaN(parsed.getTime()) ? null : parsed;
  };
  const iso = (d) => d ? d.toISOString().slice(0, 10) : "";
  const monthKey = (v) => {
    const d = parseDate(v);
    return d ? `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, "0")}` : "Unknown";
  };
  const niceMonth = (m) => {
    if (m === "Unknown") return m;
    const [y, mo] = m.split("-").map(Number);
    return new Date(Date.UTC(y, mo - 1, 1)).toLocaleString("en-US", { month: "short", year: "numeric", timeZone: "UTC" });
  };
  const money = (n) => (num(n)).toLocaleString("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 });
  const int = (n) => (num(n)).toLocaleString("en-US", { maximumFractionDigits: 0 });
  const pct = (n) => `${((num(n)) * 100).toFixed(1)}%`;
  const esc = (v) => String(v ?? "").replace(/[&<>"']/g, (m) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[m]));
  const groupBy = (arr, fn) => arr.reduce((map, row) => {
    const key = fn(row) || "Unknown";
    if (!map.has(key)) map.set(key, []);
    map.get(key).push(row);
    return map;
  }, new Map());
  const sum = (arr, fn) => arr.reduce((acc, row) => acc + num(fn(row)), 0);
  const uniq = (arr, fn) => new Set(arr.map(fn).filter(Boolean));
  const isPaid = (r) => !r.isComped && !r.isRefund && num(r.price) > 0;

  function regionForCountry(country) {
    const c = norm(country);
    if (!c) return "Unknown";
    const sets = {
      "North America": ["united states", "usa", "us", "canada", "mexico"],
      Europe: ["united kingdom", "england", "scotland", "wales", "ireland", "france", "germany", "spain", "italy", "netherlands", "belgium", "switzerland", "austria", "poland", "portugal", "sweden", "norway", "denmark", "finland", "czechia", "czech republic", "greece", "hungary", "romania", "ukraine", "croatia", "serbia", "slovakia", "slovenia", "bulgaria", "lithuania", "latvia", "estonia"],
      "Asia-Pacific": ["australia", "new zealand", "japan", "china", "hong kong", "singapore", "india", "south korea", "korea", "philippines", "thailand", "malaysia", "indonesia", "vietnam", "taiwan"],
      "Latin America": ["brazil", "argentina", "chile", "colombia", "peru", "uruguay", "paraguay", "bolivia", "ecuador", "venezuela", "costa rica", "panama", "guatemala", "dominican republic"],
      "Middle East & Africa": ["israel", "united arab emirates", "uae", "saudi arabia", "qatar", "south africa", "egypt", "morocco", "turkey"],
    };
    for (const [region, values] of Object.entries(sets)) if (values.includes(c)) return region;
    return "Other International";
  }

  function canonicalHeader(h) {
    return String(h || "").trim().replace(/^\uFEFF/, "");
  }

  function parseCsv(text) {
    const rows = [];
    let row = [];
    let cell = "";
    let inQuotes = false;
    for (let i = 0; i < text.length; i += 1) {
      const ch = text[i];
      const next = text[i + 1];
      if (inQuotes) {
        if (ch === '"' && next === '"') { cell += '"'; i += 1; }
        else if (ch === '"') inQuotes = false;
        else cell += ch;
      } else if (ch === '"') inQuotes = true;
      else if (ch === ",") { row.push(cell); cell = ""; }
      else if (ch === "\n") { row.push(cell); rows.push(row); row = []; cell = ""; }
      else if (ch !== "\r") cell += ch;
    }
    row.push(cell);
    rows.push(row);
    const headers = (rows.shift() || []).map(canonicalHeader);
    return rows.filter((r) => r.some((c) => String(c).trim())).map((r) => {
      const obj = {};
      headers.forEach((h, i) => { obj[h] = r[i] ?? ""; });
      return obj;
    });
  }

  function validateColumns(rows, required) {
    const headers = new Set(Object.keys(rows[0] || {}).map(canonicalHeader));
    return required.filter((h) => !headers.has(h));
  }

  function saveUpload(type, rows, fileName) {
    localStorage.setItem(`intro:${type}:rows`, JSON.stringify(rows));
    localStorage.setItem(`intro:${type}:meta`, JSON.stringify({ fileName, updatedAt: new Date().toISOString(), rowCount: rows.length }));
  }

  function loadUpload(type) {
    try {
      const rows = localStorage.getItem(`intro:${type}:rows`);
      const meta = localStorage.getItem(`intro:${type}:meta`);
      return rows ? { rows: JSON.parse(rows), meta: meta ? JSON.parse(meta) : null } : null;
    } catch {
      return null;
    }
  }

  function resetUploads() {
    ["bookings", "talent", "waitlist"].forEach((type) => {
      localStorage.removeItem(`intro:${type}:rows`);
      localStorage.removeItem(`intro:${type}:meta`);
    });
    hydrateData();
  }

  function normalizeTalent(row) {
    return {
      name: txt(row.name),
      key: norm(row.name),
      category: txt(row.category, "Unknown"),
      categoryOrg: txt(row.categoryOrg, "Unknown"),
      categoryStyle: txt(row.categoryStyle, "Unknown"),
      categorySub: txt(row.categorySub, "Unknown"),
      accountStatus: txt(row.accountStatus, "Unknown"),
      isAvailable: txt(row.isAvailable, "no"),
      isLive: txt(row.isLive, "no"),
      onboardingStatus: txt(row.onboardingStatus, "Unknown"),
      price: num(row.price),
      createdDate: iso(parseDate(row.createdDate)),
      allBookings: 0,
      paidBookings: 0,
      paidRevenue: 0,
      grossRevenue: 0,
      compedBookings: 0,
      uniqueGuestsSet: new Set(),
      firstBooking: "",
      lastBooking: "",
      waitlistCount: 0,
      activeWaitlist: 0,
      waitlistFansSet: new Set(),
      waitlistLast30: 0,
      waitlistLast90: 0,
    };
  }

  function normalizeBooking(row, talentMap) {
    const talentName = txt(row.coreTalent ?? row.talent, "Unknown Talent");
    const t = talentMap.get(norm(talentName));
    const status = txt(row.status, "Unknown");
    const comped = txt(row.priceComped ?? row.comped, "no");
    const price = num(row.priceFinal ?? row.price);
    return {
      talent: talentName,
      date: iso(parseDate(row.date)),
      city: txt(row.geoCity ?? row.city, "Unknown"),
      country: txt(row.geoCountry ?? row.country, "Unknown"),
      state: txt(row.geoState ?? row.state, "Unknown"),
      region: regionForCountry(row.geoCountry ?? row.country),
      comped,
      discount: num(row.priceDiscount ?? row.discount),
      price,
      guest: txt(row.primaryGuest ?? row.guest, "Unknown Guest"),
      guestKey: norm(row.primaryGuest ?? row.guest),
      status,
      isComped: norm(comped) === "yes",
      isRefund: norm(status).includes("refund"),
      category: t?.category || txt(row.category, "Unknown"),
      categoryOrg: t?.categoryOrg || txt(row.categoryOrg, "Unknown"),
      categoryStyle: t?.categoryStyle || txt(row.categoryStyle, "Unknown"),
      categorySub: t?.categorySub || txt(row.categorySub, "Unknown"),
      talentIsLive: t?.isLive || txt(row.talentIsLive, "Unknown"),
      talentOnboardingStatus: t?.onboardingStatus || txt(row.talentOnboardingStatus, "Unknown"),
    };
  }

  function normalizeWaitlist(row, talentMap) {
    const talentName = txt(row.coreTalent ?? row.talent, "Unknown Talent");
    const t = talentMap.get(norm(talentName));
    const fanEmail = txt(row.fanEmail ?? row.email);
    const fanName = txt(row.fanName ?? row.fan, fanEmail || "Unknown Fan");
    const createdDate = iso(parseDate(row["Creation Date"] ?? row.createdDate ?? row.creationDate));
    return {
      talent: talentName,
      fan: fanName,
      fanEmail,
      fanKey: norm(fanEmail || fanName),
      introAccount: txt(row.introAccount, "unknown"),
      lastNotified: iso(parseDate(row.lastNotified)),
      status: txt(row.status, "Unknown"),
      uniqueKey: txt(row.uniqueKey),
      createdDate,
      category: t?.category || "Unknown",
      categoryOrg: t?.categoryOrg || "Unknown",
      categoryStyle: t?.categoryStyle || "Unknown",
    };
  }

  function hydrateData() {
    const b = loadUpload("bookings");
    const t = loadUpload("talent");
    const w = loadUpload("waitlist");
    state.rawBookings = b?.rows || DEFAULT_BOOKINGS;
    state.rawTalent = t?.rows || DEFAULT_TALENT;
    state.rawWaitlist = w?.rows || DEFAULT_WAITLIST;

    const talentRows = state.rawTalent.map(normalizeTalent).filter((row) => row.name);
    const talentMap = new Map(talentRows.map((row) => [row.key, row]));
    const bookingRows = state.rawBookings.map((row) => normalizeBooking(row, talentMap));
    const waitlistRows = state.rawWaitlist.map((row) => normalizeWaitlist(row, talentMap));
    const maxWaitDate = waitlistRows.map((row) => parseDate(row.createdDate)).filter(Boolean).sort((a, b) => b - a)[0] || new Date();

    bookingRows.forEach((row) => {
      const trow = talentMap.get(norm(row.talent));
      if (!trow) return;
      trow.allBookings += 1;
      trow.grossRevenue += row.price;
      if (row.isComped) trow.compedBookings += 1;
      if (isPaid(row)) {
        trow.paidBookings += 1;
        trow.paidRevenue += row.price;
        if (row.guestKey) trow.uniqueGuestsSet.add(row.guestKey);
      }
      if (row.date && (!trow.firstBooking || row.date < trow.firstBooking)) trow.firstBooking = row.date;
      if (row.date && (!trow.lastBooking || row.date > trow.lastBooking)) trow.lastBooking = row.date;
    });

    waitlistRows.forEach((row) => {
      const trow = talentMap.get(norm(row.talent));
      if (!trow) return;
      trow.waitlistCount += 1;
      if (norm(row.status) === "active") trow.activeWaitlist += 1;
      if (row.fanKey) trow.waitlistFansSet.add(row.fanKey);
      const d = parseDate(row.createdDate);
      if (d) {
        const days = (maxWaitDate - d) / 86400000;
        if (days <= 30) trow.waitlistLast30 += 1;
        if (days <= 90) trow.waitlistLast90 += 1;
      }
    });

    state.talent = talentRows.map((row) => ({
      ...row,
      uniqueGuests: row.uniqueGuestsSet.size,
      waitlistFans: row.waitlistFansSet.size,
      demandGap: row.activeWaitlist - row.paidBookings,
      waitlistGrowthScore: row.waitlistLast90 / Math.max(1, row.waitlistCount - row.waitlistLast90),
    }));
    state.bookings = bookingRows;
    state.waitlist = waitlistRows;
    updateUploadStatus();
    populateFilters();
    renderAll();
  }

  function updateUploadStatus() {
    const types = ["bookings", "talent", "waitlist"];
    const rows = types.map((type) => {
      const upload = loadUpload(type);
      const label = upload ? `Using uploaded ${type}.csv` : `Using default ${type} data`;
      const meta = upload?.meta ? `${esc(upload.meta.fileName)} · ${int(upload.meta.rowCount)} rows · ${new Date(upload.meta.updatedAt).toLocaleString()}` : `Default embedded dataset · ${int((type === "bookings" ? DEFAULT_BOOKINGS : type === "talent" ? DEFAULT_TALENT : DEFAULT_WAITLIST).length)} rows`;
      return `<div class="data-status-row"><span>${label}</span><em>${meta}</em></div>`;
    });
    $("dataStatus").innerHTML = rows.join("");
  }

  function populateSelect(id, values, label) {
    const el = $(id);
    const current = el.value;
    el.innerHTML = `<option value="">${label}</option>` + [...new Set(values.filter(Boolean))].sort().map((v) => `<option value="${esc(v)}">${esc(v)}</option>`).join("");
    if ([...el.options].some((o) => o.value === current)) el.value = current;
  }

  function populateFilters() {
    populateSelect("categoryFilter", state.talent.map((t) => t.category), "All categories");
    populateSelect("styleFilter", state.talent.map((t) => t.categoryStyle), "All styles");
    populateSelect("talentFilter", state.talent.map((t) => t.name), "All talent");
    populateSelect("talentCategoryFilter", state.talent.map((t) => t.category), "All categories");
    populateSelect("onboardingFilter", state.talent.map((t) => t.onboardingStatus), "All onboarding");
    populateSelect("geoRegionFilter", state.bookings.map((r) => r.region), "All regions");
    populateSelect("geoCountryFilter", state.bookings.map((r) => r.country), "All countries");
    populateSelect("geoCategoryFilter", state.talent.map((t) => t.category), "All categories");
    populateSelect("waitCategoryFilter", state.talent.map((t) => t.category), "All categories");
    populateSelect("waitStatusFilter", state.waitlist.map((w) => w.status), "All statuses");
  }

  function syncStyleOptions() {
    const cat = $("categoryFilter").value;
    populateSelect("styleFilter", state.talent.filter((t) => !cat || t.category === cat).map((t) => t.categoryStyle), "All styles");
  }

  function setBookingRange(kind) {
    const years = state.bookings.map((r) => parseDate(r.date)).filter(Boolean).map((d) => d.getUTCFullYear());
    const maxYear = Math.max(...years, new Date().getUTCFullYear());
    const maxDate = state.bookings.map((r) => r.date).filter(Boolean).sort().at(-1) || iso(new Date());
    let start = "", end = "";
    if (kind === "all") { start = ""; end = ""; }
    else if (kind === "ytd") { start = `${maxYear}-01-01`; end = maxDate; }
    else if (kind === "last90") {
      const d = parseDate(maxDate) || new Date();
      const s = new Date(d.getTime() - 90 * 86400000);
      start = iso(s); end = iso(d);
    } else { start = `${kind}-01-01`; end = `${kind}-12-31`; }
    $("startDate").value = start; $("endDate").value = end; renderRevOps();
  }

  function setCreatedRange(kind) {
    const years = state.talent.map((t) => parseDate(t.createdDate)).filter(Boolean).map((d) => d.getUTCFullYear());
    const maxYear = Math.max(...years, new Date().getUTCFullYear());
    const maxDate = state.talent.map((t) => t.createdDate).filter(Boolean).sort().at(-1) || iso(new Date());
    let start = "", end = "";
    if (kind === "all") { start = ""; end = ""; }
    else if (kind === "ytd") { start = `${maxYear}-01-01`; end = maxDate; }
    else if (kind === "last90") {
      const d = parseDate(maxDate) || new Date();
      const s = new Date(d.getTime() - 90 * 86400000);
      start = iso(s); end = iso(d);
    } else { start = `${kind}-01-01`; end = `${kind}-12-31`; }
    $("createdStart").value = start; $("createdEnd").value = end; renderTalentOps();
  }

  function resetRevFilters() {
    ["categoryFilter", "styleFilter", "talentFilter", "compedFilter"].forEach((id) => { $(id).value = ""; });
    syncStyleOptions(); setBookingRange("all");
  }

  function resetTalentFilters() {
    ["talentCategoryFilter", "liveFilter", "onboardingFilter"].forEach((id) => { $(id).value = ""; });
    setCreatedRange("all");
  }

  function resetGeoFilters() {
    ["geoRegionFilter", "geoCountryFilter", "geoCategoryFilter"].forEach((id) => { $(id).value = ""; });
    renderPurchaser();
  }

  function resetWaitFilters() {
    ["waitCategoryFilter", "waitStatusFilter"].forEach((id) => { $(id).value = ""; });
    renderWaitlist();
  }

  function showTab(id) {
    state.activeTab = id;
    document.querySelectorAll(".tab").forEach((el) => el.classList.toggle("active", el.id === id));
    document.querySelectorAll(".tabbtn").forEach((el) => el.classList.toggle("active", el.dataset.tab === id));
  }

  function getFilteredBookings() {
    const start = $("startDate").value, end = $("endDate").value;
    const cat = $("categoryFilter").value, style = $("styleFilter").value, talent = $("talentFilter").value, comped = $("compedFilter").value;
    return state.bookings.filter((r) => {
      if (start && r.date < start) return false;
      if (end && r.date > end) return false;
      if (cat && r.category !== cat) return false;
      if (style && r.categoryStyle !== style) return false;
      if (talent && r.talent !== talent) return false;
      if (comped && norm(r.comped) !== comped) return false;
      return true;
    });
  }

  function getFilteredTalent() {
    const start = $("createdStart").value, end = $("createdEnd").value;
    const cat = $("talentCategoryFilter").value, live = $("liveFilter").value, onboard = $("onboardingFilter").value;
    return state.talent.filter((t) => {
      if (start && t.createdDate < start) return false;
      if (end && t.createdDate > end) return false;
      if (cat && t.category !== cat) return false;
      if (live && norm(t.isLive) !== live.toLowerCase()) return false;
      if (onboard && t.onboardingStatus !== onboard) return false;
      return true;
    });
  }

  function getFilteredGeoBookings() {
    const region = $("geoRegionFilter").value, country = $("geoCountryFilter").value, cat = $("geoCategoryFilter").value;
    return state.bookings.filter((r) => isPaid(r) && (!region || r.region === region) && (!country || r.country === country) && (!cat || r.category === cat));
  }

  function getFilteredWaitlist() {
    const cat = $("waitCategoryFilter").value, status = $("waitStatusFilter").value;
    return state.waitlist.filter((r) => (!cat || r.category === cat) && (!status || r.status === status));
  }

  function renderAll() {
    renderRevOps(); renderTalentOps(); renderPurchaser(); renderWaitlist();
  }

  function kpi(id, value) { $(id).textContent = value; }

  function renderRevOps() {
    const data = getFilteredBookings();
    const paid = data.filter(isPaid);
    const paidRev = sum(paid, (r) => r.price);
    const guestRows = data.filter((r) => r.guestKey);
    const repeatGuests = [...groupBy(guestRows, (r) => r.guestKey).values()].filter((rows) => rows.length >= 2).length;
    kpi("kPaidRevenue", money(paidRev));
    kpi("kIntroRevenue", money(paidRev * TAKE_RATE));
    kpi("kPaidBookings", int(paid.length));
    kpi("kAvgPaid", money(paid.length ? paidRev / paid.length : 0));
    kpi("kMusicRev", money(sum(paid.filter((r) => r.category === "Music"), (r) => r.price)));
    kpi("kSportsRev", money(sum(paid.filter((r) => r.category === "Sports"), (r) => r.price)));
    kpi("kUniqueGuests", int(uniq(guestRows, (r) => r.guestKey).size));
    kpi("kRepeatRate", pct(uniq(guestRows, (r) => r.guestKey).size ? repeatGuests / uniq(guestRows, (r) => r.guestKey).size : 0));
    renderTrend(data);
    renderBars("categoryBars", data, (r) => r.category, (rows) => sum(rows.filter(isPaid), (x) => x.price), "fill");
    renderBars("styleBars", data, (r) => r.categoryStyle, (rows) => sum(rows.filter(isPaid), (x) => x.price), "fill2", 10);
    renderRevTalentTable(data);
    renderGuests(data);
    renderDiscounts(data);
    renderBookings(data);
    renderReadout(data);
  }

  function renderTrend(data) {
    const by = groupBy(data, (r) => monthKey(r.date));
    const points = [...by.keys()].filter((k) => k !== "Unknown").sort().map((k) => {
      const paid = (by.get(k) || []).filter(isPaid);
      return { month: k, revenue: sum(paid, (r) => r.price), bookings: paid.length };
    });
    drawLineChart("trendChart", points, "revenue", "bookings", true);
  }

  function renderBars(id, data, keyFn, valFn, fillClass = "fill", limit = 12, valueFormatter = money) {
    const rows = [...groupBy(data, keyFn).entries()].map(([key, rows]) => ({ key, count: rows.length, val: valFn(rows) })).filter((r) => r.val > 0 || r.count > 0).sort((a, b) => b.val - a.val).slice(0, limit);
    const max = Math.max(1, ...rows.map((r) => r.val || r.count));
    $(id).innerHTML = rows.map((r) => `<div class="barrow"><div class="mini"><b>${esc(r.key)}</b><br>${int(r.count)} rows</div><div class="bar"><div class="${fillClass}" style="width:${((r.val || r.count) / max) * 100}%"></div></div><div class="mini">${valueFormatter(r.val)}</div></div>`).join("") || `<div class="mini">No data</div>`;
  }

  function renderRevTalentTable(data) {
    const rows = [...groupBy(data, (r) => r.talent).entries()].map(([name, rows]) => {
      const paid = rows.filter(isPaid); const rev = sum(paid, (r) => r.price);
      return { name, cat: rows[0]?.category, style: rows[0]?.categoryStyle, rev, intro: rev * TAKE_RATE, paid: paid.length, avg: paid.length ? rev / paid.length : 0 };
    }).sort((a, b) => b.rev - a.rev).slice(0, 20);
    $("revTalentRows").innerHTML = rows.map((r) => `<tr><td><b>${esc(r.name)}</b></td><td>${esc(r.cat)}</td><td>${esc(r.style)}</td><td>${money(r.rev)}</td><td>${money(r.intro)}</td><td>${int(r.paid)}</td><td>${money(r.avg)}</td></tr>`).join("") || `<tr><td colspan="7">No data</td></tr>`;
  }

  function renderGuests(data) {
    const rows = [...groupBy(data.filter((r) => r.guestKey), (r) => r.guestKey).values()].map((rows) => {
      const paid = rows.filter(isPaid), talentCounts = {};
      rows.forEach((r) => { talentCounts[r.talent] = (talentCounts[r.talent] || 0) + 1; });
      return { guest: rows[0].guest, bookings: rows.length, rev: sum(paid, (r) => r.price), top: Object.entries(talentCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || "" };
    }).filter((r) => r.bookings > 1).sort((a, b) => b.bookings - a.bookings || b.rev - a.rev).slice(0, 12);
    $("guestRows").innerHTML = rows.map((r) => `<tr><td><b>${esc(r.guest)}</b></td><td>${int(r.bookings)}</td><td>${money(r.rev)}</td><td>${esc(r.top)}</td></tr>`).join("") || `<tr><td colspan="4">No repeat guests</td></tr>`;
  }

  function renderDiscounts(data) {
    const comp = data.filter((r) => r.isComped), disc = data.filter((r) => r.discount > 0), refunds = data.filter((r) => r.isRefund);
    $("discountWatch").innerHTML = `<div class="barrow"><div class="mini"><b>Comped rows</b></div><div class="bar"><div class="fill" style="width:${data.length ? comp.length / data.length * 100 : 0}%"></div></div><div class="mini">${int(comp.length)}</div></div><div class="mini">Comped face value: <b>${money(sum(comp, (r) => r.price))}</b></div><br><div class="barrow"><div class="mini"><b>Discounted rows</b></div><div class="bar"><div class="fill2" style="width:${data.length ? disc.length / data.length * 100 : 0}%"></div></div><div class="mini">${int(disc.length)}</div></div><div class="mini">Discount value in file: <b>${money(sum(disc, (r) => r.discount))}</b></div><br><div class="mini">Refund rows: <b>${int(refunds.length)}</b> · Refund row value: <b>${money(sum(refunds, (r) => r.price))}</b></div>`;
  }

  function renderBookings(data) {
    const rows = [...data].sort((a, b) => String(b.date).localeCompare(String(a.date))).slice(0, 12);
    $("bookingRows").innerHTML = rows.map((r) => `<tr><td>${esc(r.date)}</td><td><b>${esc(r.talent)}</b></td><td>${esc(r.category)}</td><td>${money(r.price)}</td><td>${pill(r.status)}</td></tr>`).join("") || `<tr><td colspan="5">No bookings</td></tr>`;
  }

  function renderReadout(data) {
    const paid = data.filter(isPaid), paidRev = sum(paid, (r) => r.price);
    const sportsRev = sum(paid.filter((r) => r.category === "Sports"), (r) => r.price);
    const musicRev = sum(paid.filter((r) => r.category === "Music"), (r) => r.price);
    const top = [...groupBy(data, (r) => r.talent).entries()].map(([talent, rows]) => ({ talent, rev: sum(rows.filter(isPaid), (r) => r.price), bookings: rows.filter(isPaid).length })).sort((a, b) => b.rev - a.rev)[0];
    const bullets = [`<b>${money(paidRev)}</b> paid revenue across <b>${int(paid.length)}</b> paid bookings; estimated Intro revenue is <b>${money(paidRev * TAKE_RATE)}</b>.`, `Music contributed <b>${money(musicRev)}</b>; Sports contributed <b>${money(sportsRev)}</b>.`, top ? `<b>${esc(top.talent)}</b> is the top revenue driver at <b>${money(top.rev)}</b> across <b>${int(top.bookings)}</b> paid bookings.` : "No top talent in the selected filter set."];
    $("readout").innerHTML = `<ul>${bullets.map((b) => `<li>${b}</li>`).join("")}</ul>`;
  }

  function renderTalentOps() {
    const rows = getFilteredTalent();
    const total = rows.length;
    const live = rows.filter((t) => norm(t.isLive) === "yes").length;
    const avail = rows.filter((t) => norm(t.isAvailable) === "yes").length;
    const completed = rows.filter((t) => norm(t.onboardingStatus) === "completed").length;
    const music = rows.filter((t) => t.category === "Music").length;
    const sports = rows.filter((t) => t.category === "Sports").length;
    const sales = rows.filter((t) => t.paidBookings > 0).length;
    const liveNoSales = rows.filter((t) => norm(t.isLive) === "yes" && t.paidBookings === 0).length;
    kpi("tTotal", int(total)); kpi("tLive", int(live)); kpi("tAvailable", int(avail)); kpi("tCompleted", int(completed)); kpi("tMusic", int(music)); kpi("tSports", int(sports)); kpi("tWithSales", int(sales)); kpi("tLiveNoSales", int(liveNoSales));
    renderOnboardChart(rows);
    renderCountBars("talentCategoryBars", rows, (t) => t.category, 8);
    renderCountBars("talentStyleBars", rows, (t) => t.categoryStyle, 12);
    renderMasterTalent(rows);
    renderFunnel(rows);
    renderCoverage(rows);
    renderNewTalent(rows);
    renderTalentReadout(rows);
  }

  function renderOnboardChart(rows) {
    const by = groupBy(rows, (t) => monthKey(t.createdDate));
    const points = [...by.keys()].filter((k) => k !== "Unknown").sort().map((k) => {
      const rs = by.get(k) || [];
      return { month: k, all: rs.length, sports: rs.filter((t) => t.category === "Sports").length, music: rs.filter((t) => t.category === "Music").length };
    });
    drawThreeLineChart("onboardChart", points, "all", "sports", "music");
  }

  function renderCountBars(id, rows, keyFn, limit = 10) {
    const items = [...groupBy(rows, keyFn).entries()].map(([key, rows]) => ({ key, count: rows.length })).sort((a, b) => b.count - a.count).slice(0, limit);
    const max = Math.max(1, ...items.map((i) => i.count));
    $(id).innerHTML = items.map((i) => `<div class="barrow"><div class="mini"><b>${esc(i.key)}</b></div><div class="bar"><div class="fill" style="width:${(i.count / max) * 100}%"></div></div><div class="mini">${int(i.count)}</div></div>`).join("") || `<div class="mini">No data</div>`;
  }

  function sortTalent(rows) {
    const field = state.sortTalentBy, dir = state.sortTalentDir === "asc" ? 1 : -1;
    return [...rows].sort((a, b) => {
      const av = field === "createdDate" || field === "lastBooking" ? String(a[field] || "") : num(a[field]);
      const bv = field === "createdDate" || field === "lastBooking" ? String(b[field] || "") : num(b[field]);
      return av > bv ? dir : av < bv ? -dir : 0;
    });
  }

  function renderMasterTalent(rows) {
    const sorted = sortTalent(rows).slice(0, 80);
    $("masterTalentRows").innerHTML = sorted.map((t) => `<tr><td><b>${esc(t.name)}</b><div class="mini">${esc(t.categoryOrg)}</div></td><td>${esc(t.category)}</td><td>${esc(t.categoryStyle)}</td><td>${pill(t.isLive)}</td><td>${pill(t.isAvailable)}</td><td>${pill(t.onboardingStatus)}</td><td>${money(t.price)}</td><td>${int(t.allBookings)}</td><td>${money(t.paidRevenue)}</td><td>${int(t.paidBookings)}</td><td>${int(t.waitlistCount)}</td><td>${esc(t.createdDate)}</td><td>${esc(t.lastBooking)}</td></tr>`).join("") || `<tr><td colspan="13">No talent</td></tr>`;
  }

  function renderFunnel(rows) {
    const items = [
      ["Roster", rows.length],
      ["Active", rows.filter((t) => norm(t.accountStatus) === "active").length],
      ["Completed onboarding", rows.filter((t) => norm(t.onboardingStatus) === "completed").length],
      ["Live", rows.filter((t) => norm(t.isLive) === "yes").length],
      ["Available", rows.filter((t) => norm(t.isAvailable) === "yes").length],
    ];
    renderNamedBars("funnel", items);
  }

  function renderCoverage(rows) {
    const items = [
      ["With paid sales", rows.filter((t) => t.paidBookings > 0).length],
      ["No paid sales", rows.filter((t) => t.paidBookings === 0).length],
      ["Live no sales", rows.filter((t) => norm(t.isLive) === "yes" && t.paidBookings === 0).length],
      ["Available no sales", rows.filter((t) => norm(t.isAvailable) === "yes" && t.paidBookings === 0).length],
    ];
    renderNamedBars("coverage", items);
  }

  function renderNamedBars(id, items) {
    const max = Math.max(1, ...items.map((i) => i[1]));
    $(id).innerHTML = items.map(([label, value]) => `<div class="barrow"><div class="mini"><b>${esc(label)}</b></div><div class="bar"><div class="fill3" style="width:${value / max * 100}%"></div></div><div class="mini">${int(value)}</div></div>`).join("");
  }

  function renderNewTalent(rows) {
    const latest = [...rows].sort((a, b) => String(b.createdDate).localeCompare(String(a.createdDate))).slice(0, 12);
    $("newTalentRows").innerHTML = latest.map((t) => `<tr><td>${esc(t.createdDate)}</td><td><b>${esc(t.name)}</b></td><td>${esc(t.category)}</td><td>${esc(t.categoryStyle)}</td><td>${pill(t.isLive)}</td></tr>`).join("") || `<tr><td colspan="5">No talent</td></tr>`;
  }

  function renderTalentReadout(rows) {
    const total = rows.length, music = rows.filter((t) => t.category === "Music").length, sports = rows.filter((t) => t.category === "Sports").length;
    const live = rows.filter((t) => norm(t.isLive) === "yes").length, liveNoSales = rows.filter((t) => norm(t.isLive) === "yes" && t.paidBookings === 0).length, withSales = rows.filter((t) => t.paidBookings > 0).length;
    const top = [...rows].sort((a, b) => b.paidRevenue - a.paidRevenue)[0];
    $("talentReadout").innerHTML = `<ul><li>Selected roster includes <b>${int(total)}</b> talent: <b>${int(music)}</b> Music and <b>${int(sports)}</b> Sports.</li><li><b>${int(live)}</b> are live; <b>${int(liveNoSales)}</b> are live but have no paid sales.</li><li><b>${int(withSales)}</b> talent have generated at least one paid booking all-time.</li><li>Top all-time revenue talent in this roster view is <b>${esc(top?.name || "n/a")}</b> at <b>${money(top?.paidRevenue || 0)}</b>.</li></ul>`;
  }

  function renderPurchaser() {
    const data = getFilteredGeoBookings();
    const revenue = sum(data, (r) => r.price);
    kpi("gRevenue", money(revenue)); kpi("gBookings", int(data.length)); kpi("gAvg", money(data.length ? revenue / data.length : 0)); kpi("gBuyers", int(uniq(data, (r) => r.guestKey).size)); kpi("gCountries", int(uniq(data, (r) => r.country !== "Unknown" ? r.country : "").size)); kpi("gRegions", int(uniq(data, (r) => r.region !== "Unknown" ? r.region : "").size));
    renderBars("regionBars", data, (r) => r.region, (rows) => sum(rows, (x) => x.price), "fill", 10);
    renderBars("countryBars", data, (r) => r.country, (rows) => sum(rows, (x) => x.price), "fill2", 14);
    renderGeoTable(data);
    renderBuyerGeo(data);
  }

  function renderGeoTable(data) {
    const rows = [...groupBy(data, (r) => `${r.region}|${r.country}|${r.state}|${r.city}`).entries()].map(([key, rows]) => {
      const [region, country, state, city] = key.split("|");
      return { region, country, state, city, revenue: sum(rows, (r) => r.price), bookings: rows.length, buyers: uniq(rows, (r) => r.guestKey).size, talent: uniq(rows, (r) => r.talent).size };
    }).sort((a, b) => b.revenue - a.revenue).slice(0, 40);
    $("geoRows").innerHTML = rows.map((r) => `<tr><td>${esc(r.region)}</td><td>${esc(r.country)}</td><td>${esc(r.state)}</td><td>${esc(r.city)}</td><td>${money(r.revenue)}</td><td>${int(r.bookings)}</td><td>${int(r.buyers)}</td><td>${int(r.talent)}</td></tr>`).join("") || `<tr><td colspan="8">No geo data</td></tr>`;
  }

  function renderBuyerGeo(data) {
    const rows = [...groupBy(data.filter((r) => r.guestKey), (r) => r.guestKey).values()].map((rows) => {
      const talentCounts = {};
      rows.forEach((r) => { talentCounts[r.talent] = (talentCounts[r.talent] || 0) + 1; });
      return { buyer: rows[0].guest, region: rows[0].region, country: rows[0].country, bookings: rows.length, revenue: sum(rows, (r) => r.price), top: Object.entries(talentCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || "" };
    }).sort((a, b) => b.bookings - a.bookings || b.revenue - a.revenue).slice(0, 20);
    $("buyerGeoRows").innerHTML = rows.map((r) => `<tr><td><b>${esc(r.buyer)}</b></td><td>${esc(r.region)}</td><td>${esc(r.country)}</td><td>${int(r.bookings)}</td><td>${money(r.revenue)}</td><td>${esc(r.top)}</td></tr>`).join("") || `<tr><td colspan="6">No buyers</td></tr>`;
  }

  function renderWaitlist() {
    const data = getFilteredWaitlist();
    const talentWithWait = uniq(data, (r) => r.talent).size;
    const talentBase = $("waitCategoryFilter").value ? state.talent.filter((t) => t.category === $("waitCategoryFilter").value).length : state.talent.length;
    const active = data.filter((r) => norm(r.status) === "active").length;
    const fans = uniq(data, (r) => r.fanKey).size;
    const multiFans = [...groupBy(data.filter((r) => r.fanKey), (r) => r.fanKey).values()].filter((rows) => rows.length >= 2).length;
    const maxDate = data.map((r) => parseDate(r.createdDate)).filter(Boolean).sort((a, b) => b - a)[0] || new Date();
    const last90 = data.filter((r) => { const d = parseDate(r.createdDate); return d && (maxDate - d) / 86400000 <= 90; }).length;
    kpi("wTotal", int(data.length)); kpi("wActive", int(active)); kpi("wTalent", int(talentWithWait)); kpi("wCoverage", pct(talentBase ? talentWithWait / talentBase : 0)); kpi("wFans", int(fans)); kpi("wMultiFans", int(multiFans)); kpi("wLast90", int(last90)); kpi("wActiveRate", pct(data.length ? active / data.length : 0));
    renderWaitTrend(data);
    renderWaitTalent(data);
    renderFastWaitlist();
    renderEngagedFans(data);
    renderWaitCategory(data);
    renderWaitReadout(data);
  }

  function renderWaitTrend(data) {
    const by = groupBy(data, (r) => monthKey(r.createdDate));
    let cumulative = 0;
    const points = [...by.keys()].filter((k) => k !== "Unknown").sort().map((k) => {
      const rows = by.get(k) || [];
      cumulative += rows.length;
      return { month: k, adds: rows.length, active: rows.filter((r) => norm(r.status) === "active").length, cumulative };
    });
    drawThreeLineChart("waitTrendChart", points, "adds", "active", "cumulative");
  }

  function renderWaitTalent(data) {
    const metrics = new Map(state.talent.map((t) => [t.name, t]));
    const rows = [...groupBy(data, (r) => r.talent).entries()].map(([talent, rows]) => {
      const t = metrics.get(talent) || {};
      return { talent, category: rows[0]?.category, style: rows[0]?.categoryStyle, count: rows.length, active: rows.filter((r) => norm(r.status) === "active").length, fans: uniq(rows, (r) => r.fanKey).size, paid: t.paidBookings || 0, revenue: t.paidRevenue || 0, gap: rows.length - (t.paidBookings || 0) };
    }).sort((a, b) => b.count - a.count).slice(0, 20);
    $("waitTalentRows").innerHTML = rows.map((r) => `<tr><td><b>${esc(r.talent)}</b></td><td>${esc(r.category)}</td><td>${esc(r.style)}</td><td>${int(r.count)}</td><td>${int(r.active)}</td><td>${int(r.fans)}</td><td>${int(r.paid)}</td><td>${money(r.revenue)}</td><td>${int(r.gap)}</td></tr>`).join("") || `<tr><td colspan="9">No waitlist data</td></tr>`;
    const barData = rows.slice(0, 12).map((r) => ({ key: r.talent, count: r.count }));
    const max = Math.max(1, ...barData.map((r) => r.count));
    $("topWaitBars").innerHTML = barData.map((r) => `<div class="barrow"><div class="mini"><b>${esc(r.key)}</b></div><div class="bar"><div class="fill" style="width:${r.count / max * 100}%"></div></div><div class="mini">${int(r.count)}</div></div>`).join("") || `<div class="mini">No waitlist data</div>`;
  }

  function renderFastWaitlist() {
    const rows = [...state.talent].filter((t) => t.waitlistLast90 > 0).sort((a, b) => b.waitlistLast90 - a.waitlistLast90 || b.waitlistGrowthScore - a.waitlistGrowthScore).slice(0, 20);
    $("fastWaitRows").innerHTML = rows.map((t) => `<tr><td><b>${esc(t.name)}</b></td><td>${esc(t.category)}</td><td>${esc(t.categoryStyle)}</td><td>${int(t.waitlistLast30)}</td><td>${int(t.waitlistLast90)}</td><td>${t.waitlistGrowthScore.toFixed(1)}x</td><td>${int(t.waitlistCount)}</td><td>${int(t.demandGap)}</td></tr>`).join("") || `<tr><td colspan="8">No recent waitlist growth</td></tr>`;
  }

  function renderEngagedFans(data) {
    const rows = [...groupBy(data.filter((r) => r.fanKey), (r) => r.fanKey).values()].map((rows) => ({
      fan: rows[0].fan,
      email: rows[0].fanEmail,
      joined: rows.length,
      active: rows.filter((r) => norm(r.status) === "active").length,
      talent: uniq(rows, (r) => r.talent).size,
      topCategory: [...groupBy(rows, (r) => r.category).entries()].sort((a, b) => b[1].length - a[1].length)[0]?.[0] || "",
      first: rows.map((r) => r.createdDate).filter(Boolean).sort()[0] || "",
      last: rows.map((r) => r.createdDate).filter(Boolean).sort().at(-1) || "",
    })).sort((a, b) => b.joined - a.joined || b.talent - a.talent).slice(0, 20);
    $("fanRows").innerHTML = rows.map((r) => `<tr><td><b>${esc(r.fan)}</b><div class="mini">${esc(r.email)}</div></td><td>${int(r.joined)}</td><td>${int(r.active)}</td><td>${int(r.talent)}</td><td>${esc(r.topCategory)}</td><td>${esc(r.first)}</td><td>${esc(r.last)}</td></tr>`).join("") || `<tr><td colspan="7">No fan data</td></tr>`;
  }

  function renderWaitCategory(data) {
    renderBars("waitCategoryBars", data, (r) => r.category, (rows) => rows.length, "fill3", 8, int);
    renderBars("waitStyleBars", data, (r) => r.categoryStyle, (rows) => rows.length, "fill2", 12, int);
  }

  function renderWaitReadout(data) {
    const topTalent = [...groupBy(data, (r) => r.talent).entries()].map(([talent, rows]) => ({ talent, count: rows.length })).sort((a, b) => b.count - a.count)[0];
    const topFan = [...groupBy(data.filter((r) => r.fanKey), (r) => r.fanKey).values()].map((rows) => ({ fan: rows[0].fan, count: rows.length })).sort((a, b) => b.count - a.count)[0];
    $("waitReadout").innerHTML = `<ul><li><b>${int(data.length)}</b> waitlist rows show unmet demand across <b>${int(uniq(data, (r) => r.talent).size)}</b> talent.</li><li><b>${esc(topTalent?.talent || "n/a")}</b> has the largest waitlist at <b>${int(topTalent?.count || 0)}</b> rows.</li><li>Most engaged fan: <b>${esc(topFan?.fan || "n/a")}</b> joined <b>${int(topFan?.count || 0)}</b> waitlists.</li></ul>`;
  }

  function pill(value) {
    const v = txt(value, "Unknown"), n = norm(v);
    let cls = n === "yes" || n === "completed" || n === "active" || n === "booked" ? "good" : n.includes("refund") || n === "no" || n === "notactive" ? "bad" : "blue";
    return `<span class="pill ${cls}">${esc(v)}</span>`;
  }

  function drawLineChart(svgId, points, keyA, keyB) {
    const svg = $(svgId); svg.innerHTML = "";
    if (!points.length) { svg.innerHTML = `<text x="50%" y="50%" text-anchor="middle" fill="${COLORS.muted}">No data in range</text>`; return; }
    const w = svg.clientWidth || 700, h = svg.clientHeight || 270, pad = 34;
    const maxA = Math.max(1, ...points.map((p) => num(p[keyA]))), maxB = Math.max(1, ...points.map((p) => num(p[keyB])));
    const x = (i) => pad + (points.length === 1 ? 0 : i * (w - pad * 2) / (points.length - 1));
    const yA = (v) => h - pad - (num(v) / maxA) * (h - pad * 2);
    const yB = (v) => h - pad - (num(v) / maxB) * (h - pad * 2);
    svg.innerHTML += `<line class="axis" x1="${pad}" y1="${h - pad}" x2="${w - pad}" y2="${h - pad}"></line><line class="axis" x1="${pad}" y1="${pad}" x2="${pad}" y2="${h - pad}"></line>`;
    const pathA = points.map((p, i) => `${i ? "L" : "M"}${x(i)},${yA(p[keyA])}`).join(" ");
    const pathB = points.map((p, i) => `${i ? "L" : "M"}${x(i)},${yB(p[keyB])}`).join(" ");
    svg.innerHTML += `<path class="line" d="${pathA}"></path><path class="lineB" d="${pathB}"></path>`;
    points.forEach((p, i) => { if (i % Math.ceil(points.length / 8) === 0) svg.innerHTML += `<text x="${x(i)}" y="${h - 8}" text-anchor="middle" fill="${COLORS.muted}" font-size="10">${niceMonth(p.month)}</text>`; });
  }

  function drawThreeLineChart(svgId, points, keyA, keyB, keyC) {
    const svg = $(svgId); svg.innerHTML = "";
    if (!points.length) { svg.innerHTML = `<text x="50%" y="50%" text-anchor="middle" fill="${COLORS.muted}">No data in range</text>`; return; }
    const w = svg.clientWidth || 700, h = svg.clientHeight || 270, pad = 34;
    const max = Math.max(1, ...points.flatMap((p) => [num(p[keyA]), num(p[keyB]), num(p[keyC])]));
    const x = (i) => pad + (points.length === 1 ? 0 : i * (w - pad * 2) / (points.length - 1));
    const y = (v) => h - pad - (num(v) / max) * (h - pad * 2);
    svg.innerHTML += `<line class="axis" x1="${pad}" y1="${h - pad}" x2="${w - pad}" y2="${h - pad}"></line><line class="axis" x1="${pad}" y1="${pad}" x2="${pad}" y2="${h - pad}"></line>`;
    [[keyA, "line"], [keyB, "lineB"], [keyC, "lineP"]].forEach(([key, cls]) => {
      svg.innerHTML += `<path class="${cls}" d="${points.map((p, i) => `${i ? "L" : "M"}${x(i)},${y(p[key])}`).join(" ")}"></path>`;
    });
    points.forEach((p, i) => { if (i % Math.ceil(points.length / 8) === 0) svg.innerHTML += `<text x="${x(i)}" y="${h - 8}" text-anchor="middle" fill="${COLORS.muted}" font-size="10">${niceMonth(p.month)}</text>`; });
  }

  function handleUpload(type, required) {
    const input = $(`${type}Upload`);
    const file = input.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const rows = parseCsv(String(reader.result || ""));
      const missing = validateColumns(rows, required);
      if (missing.length) {
        $(`${type}UploadMsg`).innerHTML = `<span class="badtext">Missing required columns: ${missing.map(esc).join(", ")}</span>`;
        return;
      }
      saveUpload(type, rows, file.name);
      $(`${type}UploadMsg`).innerHTML = `<span class="goodtext">Loaded ${int(rows.length)} rows from ${esc(file.name)}</span>`;
      hydrateData();
    };
    reader.readAsText(file);
  }

  function wire() {
    document.querySelectorAll(".tabbtn").forEach((btn) => btn.addEventListener("click", () => showTab(btn.dataset.tab)));
    ["startDate", "endDate", "categoryFilter", "styleFilter", "talentFilter", "compedFilter"].forEach((id) => $(id).addEventListener("input", renderRevOps));
    ["createdStart", "createdEnd", "talentCategoryFilter", "liveFilter", "onboardingFilter"].forEach((id) => $(id).addEventListener("input", renderTalentOps));
    ["geoRegionFilter", "geoCountryFilter", "geoCategoryFilter"].forEach((id) => $(id).addEventListener("input", renderPurchaser));
    ["waitCategoryFilter", "waitStatusFilter"].forEach((id) => $(id).addEventListener("input", renderWaitlist));
    $("categoryFilter").addEventListener("input", syncStyleOptions);
    $("sortTalentBy").addEventListener("input", () => { state.sortTalentBy = $("sortTalentBy").value; renderTalentOps(); });
    $("sortTalentDir").addEventListener("input", () => { state.sortTalentDir = $("sortTalentDir").value; renderTalentOps(); });
    $("bookingsUpload").addEventListener("change", () => handleUpload("bookings", bookingRequired));
    $("talentUpload").addEventListener("change", () => handleUpload("talent", talentRequired));
    $("waitlistUpload").addEventListener("change", () => handleUpload("waitlist", waitlistRequired));
    $("resetDataBtn").addEventListener("click", resetUploads);
    window.setBookingRange = setBookingRange;
    window.setCreatedRange = setCreatedRange;
    window.resetRevFilters = resetRevFilters;
    window.resetTalentFilters = resetTalentFilters;
    window.resetGeoFilters = resetGeoFilters;
    window.resetWaitFilters = resetWaitFilters;
  }

  async function loadDefaultCsv(path, fallbackRows) {
    try {
      const response = await fetch(path, { cache: "no-store" });
      if (!response.ok) throw new Error("Default CSV not available");
      const rows = parseCsv(await response.text());
      return rows.length ? rows : fallbackRows;
    } catch {
      return fallbackRows;
    }
  }

  async function init() {
    DEFAULT_BOOKINGS = await loadDefaultCsv("data/default/bookings.csv", DEFAULT_BOOKINGS);
    DEFAULT_TALENT = await loadDefaultCsv("data/default/talent.csv", DEFAULT_TALENT);
    DEFAULT_WAITLIST = await loadDefaultCsv("data/default/waitlist.csv", DEFAULT_WAITLIST);
    wire();
    hydrateData();
    setBookingRange("all");
    setCreatedRange("all");
  }

  init();
})();